mapper.update:
UPDATE bluenote_counter.counter_snapshot
SET counter_value = GREATEST(0, counter_value + #{deltaValue}),
    snapshot_version = snapshot_version + 1,
    flushed_at = #{updatedAt},
    updated_at = #{updatedAt}
WHERE target_type = #{targetType}
  AND target_id = #{targetId}
  AND counter_field = #{counterField}

